const initialState = state;
const reset = () => setState(initialState as T, true);
Object.assign(api, { reset });

import { createStore } from '../vanilla';
import { expect, test, vi } from 'vitest';

test('initial state', () => {
  const store = createStore(() => ({ count: 0 }));
  expect(store.getState().count).toBe(0);
});

test('setState updates state', () => {
  const store = createStore(() => ({ count: 0 }));
  store.setState({ count: 5 });
  expect(store.getState().count).toBe(5);
});

test('subscribe fires on change', () => {
  const store = createStore(() => ({ count: 0 }));
  const listener = vi.fn();
  store.subscribe(listener);
  store.setState({ count: 1 });
  expect(listener).toHaveBeenCalled();
});

const subscribe: StoreApi<TState>['subscribe'] = (listener, selector?) => {
  if (selector) {
    let currentSlice = selector(state);
    const wrappedListener = (nextState: TState, prevState: TState) => {
      const nextSlice = selector(nextState);
      if (!Object.is(currentSlice, nextSlice)) {
        currentSlice = nextSlice;
        listener(nextState, prevState);
      }
    };
    listeners.add(wrappedListener as Listener);
    return () => listeners.delete(wrappedListener as Listener);
  }
  listeners.add(listener);
  return () => listeners.delete(listener);
}
